+    local procedure CalcQtyReservedForOtherWorksheetLines(WhseWorksheetLine: Record "Whse. Worksheet Line"): Decimal
+    var
+        OtherWhseWkshLine: Record "Whse. Worksheet Line";
+        TempWhseActivLine: Record "Warehouse Activity Line" temporary;
+        QtyReservedBase: Decimal;
+        TotalQtyReservedBase: Decimal;
+    begin
+        OtherWhseWkshLine.SetCurrentKey("Item No.", "Location Code", "Worksheet Template Name", "Variant Code");
+        OtherWhseWkshLine.SetRange("Item No.", WhseWorksheetLine."Item No.");
+        OtherWhseWkshLine.SetRange("Location Code", WhseWorksheetLine."Location Code");
+        OtherWhseWkshLine.SetRange("Worksheet Template Name", WhseWorksheetLine."Worksheet Template Name");
+        OtherWhseWkshLine.SetRange("Variant Code", WhseWorksheetLine."Variant Code");
+        
+        if OtherWhseWkshLine.Find('-') then
+            repeat
+                if OtherWhseWkshLine.RecordId <> WhseWorksheetLine.RecordId then begin
+                    QtyReservedBase := Abs(CalcLineReservedQtyOnInvt(
