+                        OtherWhseWkshLine."Source No.", OtherWhseWkshLine."Source Line No.",
+                        OtherWhseWkshLine."Source Subline No.", true, TempWhseActivLine));
+                    if QtyReservedBase > 0 then
+                        TotalQtyReservedBase += QtyReservedBase;
+                end;
+            until OtherWhseWkshLine.Next() = 0;
+        
+        exit(TotalQtyReservedBase);
+    end;
